import { createSlice } from '@reduxjs/toolkit'

const initialState = {
    items : [],
    originalTotal :0,
    finalTotal : 0
}

export const cartSlice = createSlice({
  name: 'cart',
  initialState,
  reducers: {
    addToCart: (state,{payload}) => {
     state.items.push(payload);
     state.originalTotal += Number(payload?.original_price);
     state.finalTotal += Number(payload?.final_price);

     
    },
    
    emptyCart : (state)=>{

    },

    qtyChanges : ()=>{

    }

   
  },
})

// Action creators are generated for each case reducer function
export const { addToCart, emptyCart, qtyChanges } = cartSlice.actions

export default cartSlice.reducer